(() => {
  "use strict";
  const VERSION="V27-20260715", PANEL_ID="mom-ai-v27-panel", STYLE_ID="mom-ai-v27-style";
  const STOCKS=[
    {code:"4958",name:"臻鼎-KY",theme:"ABF",buy:[610,619],watch:[620,630],sell:[635,645],stop:606,note:"今日由656回落至616附近，只接支撐，不追開高。"},
    {code:"3189",name:"景碩",theme:"ABF／處置股",buy:[800,820],watch:[821,835],sell:[842,859],stop:795,note:"處置期間節奏可能失真，小量分批，先看800～820承接。"},
    {code:"8046",name:"南電",theme:"ABF",buy:[1320,1350],watch:[1351,1390],sell:[1400,1415],stop:1300,note:"今日漲停，不追；只等開板後回測。"},
    {code:"3037",name:"欣興",theme:"ABF",buy:[900,918],watch:[919,935],sell:[942,960],stop:890,note:"接近前高，追價風險高；等急拉後回測。"},
    {code:"6442",name:"光聖",theme:"光通訊",buy:[1330,1360],watch:[1361,1395],sell:[1410,1430],stop:1310,note:"收1430接近漲停，屬反彈確認，不是安全追價點。"},
    {code:"6770",name:"力積電",theme:"記憶體",buy:[69,72],watch:[72.1,74],sell:[75,76.1],stop:67.8,note:"只等回測；70附近量縮止穩才小量。"},
    {code:"3711",name:"日月光投控",theme:"封測",buy:[660,670],watch:[671,680],sell:[684,696],stop:654,note:"今日已大漲，680以上不追。"},
    {code:"6239",name:"力成",theme:"封測／記憶體",buy:[308,313],watch:[314,318],sell:[320,326],stop:304,note:"短線先看321壓力與308防守。"}
  ];
  const num=v=>{const m=String(v??"").replace(/,/g,"").match(/-?\d+(?:\.\d+)?/);return m?Number(m[0]):null;};
  function findLivePrice(code,name){for(const tr of document.querySelectorAll("tr")){const t=(tr.innerText||"").replace(/\s+/g," ");if(t.includes(code)||t.includes(name)){for(const c of tr.querySelectorAll("td,th")){const n=num(c.innerText);if(n!==null&&n>0&&n!==Number(code))return n;}}}return null;}
  function classify(s,p){if(p==null)return{label:"等待即時價",cls:"neutral",action:"查看DDE後再判斷"};if(p<s.stop)return{label:"先停手",cls:"danger",action:`跌破 ${s.stop}，不接第一刀`};if(p>=s.buy[0]&&p<=s.buy[1])return{label:"可分批低接",cls:"ok",action:`低接 ${s.buy[0]}～${s.buy[1]}`};if(p>=s.watch[0]&&p<=s.watch[1])return{label:"等回測",cls:"wait",action:`等回到 ${s.buy[0]}～${s.buy[1]}`};if(p>=s.sell[0])return{label:"禁止追高",cls:"hot",action:`第一波目標 ${s.sell[0]}～${s.sell[1]}`};return{label:"觀察",cls:"neutral",action:`第一波目標 ${s.sell[0]}～${s.sell[1]}`};}
  function addStyle(){if(document.getElementById(STYLE_ID))return;const e=document.createElement("style");e.id=STYLE_ID;e.textContent=`#${PANEL_ID}{font-family:system-ui,-apple-system,"Segoe UI","Noto Sans TC",sans-serif;margin:12px auto 18px;max-width:1180px;padding:14px;border-radius:18px;background:linear-gradient(145deg,#0b1528,#101f38);color:#eef6ff;box-shadow:0 10px 30px rgba(0,0,0,.22);border:1px solid rgba(103,213,255,.22)}#${PANEL_ID} *{box-sizing:border-box}#${PANEL_ID} h2{margin:0 0 6px;font-size:24px}#${PANEL_ID} .sub{opacity:.78;font-size:13px;margin-bottom:12px}#${PANEL_ID} .headline{padding:12px;border-radius:14px;background:#132844;margin-bottom:12px}#${PANEL_ID} .grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(245px,1fr));gap:10px}#${PANEL_ID} .card{background:#0e1b30;border:1px solid rgba(255,255,255,.09);border-radius:14px;padding:12px;min-height:154px}#${PANEL_ID} .top{display:flex;justify-content:space-between;gap:8px;align-items:center}#${PANEL_ID} .name{font-weight:800;font-size:18px}#${PANEL_ID} .theme{font-size:12px;opacity:.7}#${PANEL_ID} .price{font-size:22px;font-weight:800;margin:8px 0}#${PANEL_ID} .pill{display:inline-block;border-radius:999px;padding:4px 9px;font-weight:800;font-size:12px}#${PANEL_ID} .ok{background:#0f5f48;color:#d8fff2}#${PANEL_ID} .wait{background:#6c5512;color:#fff1b8}#${PANEL_ID} .hot{background:#783545;color:#ffe2e9}#${PANEL_ID} .danger{background:#8a2222;color:#fff}#${PANEL_ID} .neutral{background:#334155;color:#e2e8f0}#${PANEL_ID} .action{font-weight:800;margin:8px 0 5px}#${PANEL_ID} .note{font-size:13px;line-height:1.5;opacity:.86}#${PANEL_ID} .foot{font-size:12px;opacity:.66;margin-top:12px}@media(max-width:600px){#${PANEL_ID}{margin:8px 6px;padding:11px}#${PANEL_ID} h2{font-size:20px}}`;document.head.appendChild(e);}
  function render(){addStyle();document.getElementById(PANEL_ID)?.remove();const p=document.createElement("section");p.id=PANEL_ID;const cards=STOCKS.map(s=>{const price=findLivePrice(s.code,s.name),r=classify(s,price);return `<article class="card"><div class="top"><div><div class="name">${s.code} ${s.name}</div><div class="theme">${s.theme}</div></div><span class="pill ${r.cls}">${r.label}</span></div><div class="price">${price==null?"即時價待讀取":`現價 ${price}`}</div><div class="action">${r.action}</div><div class="note">第一波目標：${s.sell[0]}～${s.sell[1]}｜防守：${s.stop}<br>${s.note}</div></article>`}).join("");p.innerHTML=`<h2>今日低接雷達｜${VERSION}</h2><div class="sub">公開版：不顯示任何人持股成本、不顯示分析師或節目名稱。價格以頁面DDE資料為準。</div><div class="headline"><b>明日主線：</b>ABF仍是重點，但南電、欣興已大漲，優先等臻鼎、景碩回測；光聖只等回測，不追漲停附近。</div><div class="grid">${cards}</div><div class="foot">判斷順序：支撐區 → 量縮止穩 → 第一波目標價。開高越過低接區時，寧可不買。</div>`;(document.querySelector("main")||document.body).prepend(p);}
  function boot(){render();setTimeout(render,2500);setInterval(render,60000);}document.readyState==="loading"?document.addEventListener("DOMContentLoaded",boot):boot();
})();
